/**
 * Hybrid sort: Timsort-inspired approach using insertion sort for small runs
 * and a merge strategy for larger arrays. Performs well on nearly-sorted data.
 */

const INSERTION_SORT_THRESHOLD = 32;

function insertionSort(arr: number[], left: number, right: number): void {
  for (let i = left + 1; i <= right; i++) {
    const key = arr[i];
    let j = i - 1;
    while (j >= left && arr[j] > key) {
      arr[j + 1] = arr[j];
      j--;
    }
    arr[j + 1] = key;
  }
}

function merge(arr: number[], left: number, mid: number, right: number, buffer: number[]): void {
  const leftLen = mid - left + 1;
  const rightLen = right - mid;

  for (let i = 0; i < leftLen; i++) buffer[i] = arr[left + i];

  let i = 0;
  let j = mid + 1;
  let k = left;

  while (i < leftLen && j <= right) {
    if (buffer[i] <= arr[j]) {
      arr[k++] = buffer[i++];
    } else {
      arr[k++] = arr[j++];
    }
  }

  while (i < leftLen) {
    arr[k++] = buffer[i++];
  }
}

function timSort(arr: number[], buffer: number[]): void {
  const n = arr.length;

  for (let i = 0; i < n; i += INSERTION_SORT_THRESHOLD) {
    insertionSort(arr, i, Math.min(i + INSERTION_SORT_THRESHOLD - 1, n - 1));
  }

  for (let size = INSERTION_SORT_THRESHOLD; size < n; size *= 2) {
    for (let left = 0; left < n; left += 2 * size) {
      const mid = Math.min(left + size - 1, n - 1);
      const right = Math.min(left + 2 * size - 1, n - 1);
      if (mid < right) {
        merge(arr, left, mid, right, buffer);
      }
    }
  }
}

export default function optimizedSort(arr: number[]): number[] {
  if (!Array.isArray(arr)) return arr;

  const n = arr.length;

  if (n <= 1) return arr;
  if (n === 2) {
    if (arr[0] > arr[1]) {
      const tmp = arr[0];
      arr[0] = arr[1];
      arr[1] = tmp;
    }
    return arr;
  }

  if (n <= INSERTION_SORT_THRESHOLD) {
    insertionSort(arr, 0, n - 1);
    return arr;
  }

  const buffer = new Array(Math.ceil(n / 2));
  timSort(arr, buffer);

  return arr;
}

