        result.host = ipv6Match[1];
        result.port = ipv6Match[2] ? parseInt(ipv6Match[2], 10) : null;
      } else {
        const colonIndex = hostPart.lastIndexOf(":");
        if (colonIndex !== -1) {
          const potentialPort = hostPart.slice(colonIndex + 1);
