/**
 * Timsort — O(n log n) worst-case, O(n) on nearly-sorted data.
 * Sorts the array in-place and returns it.
 */

const MIN_RUN = 32;

function calcMinRun(n: number): number {
  let r = 0;
  while (n >= MIN_RUN) {
    r |= n & 1;
    n >>= 1;
  }
  return n + r;
}

function insertionSort(
  arr: number[],
  left: number,
  right: number,
): void {
  for (let i = left + 1; i <= right; i++) {
    const key = arr[i];
    let j = i - 1;
    while (j >= left && arr[j] > key) {
      arr[j + 1] = arr[j];
      j--;
    }
    arr[j + 1] = key;
  }
}

function merge(
  arr: number[],
  left: number,
  mid: number,
  right: number,
  buffer: number[],
): void {
  const leftLen = mid - left + 1;
  const rightLen = right - mid;

  // Copy left half into buffer
  for (let i = 0; i < leftLen; i++) buffer[i] = arr[left + i];

  let i = 0;
  let j = mid + 1;
  let k = left;

  while (i < leftLen && j <= right) {
    if (buffer[i] <= arr[j]) {
      arr[k++] = buffer[i++];
    } else {
      arr[k++] = arr[j++];
    }
  }

  while (i < leftLen) arr[k++] = buffer[i++];
  // Remaining right-side elements are already in place
}

export default function optimizedSort(arr: number[]): number[] {
  const n = arr.length;

  if (n <= 1) return arr;
  if (n === 2) {
    if (arr[0] > arr[1]) [arr[0], arr[1]] = [arr[1], arr[0]];
    return arr;
  }

  // Small arrays: pure insertion sort
  if (n <= MIN_RUN) {
    insertionSort(arr, 0, n - 1);
    return arr;
  }

  const minRun = calcMinRun(n);

  // Sort individual runs with insertion sort, reversing descending runs
  for (let start = 0; start < n; start += minRun) {
    const end = Math.min(start + minRun - 1, n - 1);

    // Detect and reverse strictly descending natural run
    if (arr[start] > arr[start + 1]) {
      let runEnd = start + 1;
      while (runEnd < end && arr[runEnd] > arr[runEnd + 1]) runEnd++;
      let lo = start;
      let hi = runEnd;
      while (lo < hi) {
        [arr[lo], arr[hi]] = [arr[hi], arr[lo]];
        lo++;
        hi--;
      }
    }

    insertionSort(arr, start, end);
  }

  // Allocate merge buffer once — at most half the array size
  const buffer = new Array<number>(Math.ceil(n / 2));

  // Bottom-up merge of sorted runs
  for (let size = minRun; size < n; size *= 2) {
    for (let left = 0; left < n; left += size * 2) {
      const mid = Math.min(left + size - 1, n - 1);
      const right = Math.min(left + size * 2 - 1, n - 1);

      if (mid < right) {
        merge(arr, left, mid, right, buffer);
      }
    }
  }

  return arr;
}

