const INSERTION_SORT_THRESHOLD = 16;
const INTROSORT_DEPTH_LIMIT = (length: number): number =>
  2 * Math.floor(Math.log2(length));

function insertionSort(arr: number[], left: number, right: number): void {
  for (let i = left + 1; i <= right; i++) {
    const key = arr[i];
    let j = i - 1;
    while (j >= left && arr[j] > key) {
      arr[j + 1] = arr[j];
      j--;
    }
    arr[j + 1] = key;
  }
}

function medianOfThree(arr: number[], a: number, b: number, c: number): number {
  if (arr[a] < arr[b]) {
    if (arr[b] < arr[c]) return b;
    if (arr[a] < arr[c]) return c;
    return a;
  } else {
    if (arr[a] < arr[c]) return a;
    if (arr[b] < arr[c]) return c;
    return b;
  }
}

function swap(arr: number[], i: number, j: number): void {
  const tmp = arr[i];
  arr[i] = arr[j];
  arr[j] = tmp;
}

function partition(arr: number[], left: number, right: number): number {
  const mid = left + ((right - left) >> 1);
  const pivotIdx = medianOfThree(arr, left, mid, right);
  swap(arr, pivotIdx, right);
  const pivot = arr[right];
  let i = left - 1;

  for (let j = left; j < right; j++) {
    if (arr[j] <= pivot) {
      i++;
      swap(arr, i, j);
    }
  }

  swap(arr, i + 1, right);
  return i + 1;
}

function heapify(arr: number[], n: number, i: number, offset: number): void {
  let largest = i;
  const left = 2 * (i - offset) + 1 + offset;
  const right = 2 * (i - offset) + 2 + offset;

  if (left <= offset + n - 1 && arr[left] > arr[largest]) largest = left;
  if (right <= offset + n - 1 && arr[right] > arr[largest]) largest = right;

  if (largest !== i) {
    swap(arr, i, largest);
    heapify(arr, n, largest, offset);
  }
}

function heapSort(arr: number[], left: number, right: number): void {
  const n = right - left + 1;
  for (let i = left + Math.floor(n / 2) - 1; i >= left; i--) {
    heapify(arr, n, i, left);
  }
  for (let i = right; i > left; i--) {
    swap(arr, left, i);
    heapify(arr, i - left, left, left);
  }
}

function introsort(
  arr: number[],
  left: number,
  right: number,
  depthLimit: number
): void {
  const size = right - left + 1;

  if (size <= INSERTION_SORT_THRESHOLD) {
    insertionSort(arr, left, right);
    return;
  }

  if (depthLimit === 0) {
    heapSort(arr, left, right);
    return;
  }

  const pivotIdx = partition(arr, left, right);
  introsort(arr, left, pivotIdx - 1, depthLimit - 1);
  introsort(arr, pivotIdx + 1, right, depthLimit - 1);
}

export default function optimizedSort(arr: number[]): number[] {
  if (!Array.isArray(arr) || arr.length <= 1) return arr;

  const n = arr.length;

  if (n === 2) {
    if (arr[0] > arr[1]) swap(arr, 0, 1);
    return arr;
  }

  const depthLimit = INTROSORT_DEPTH_LIMIT(n);
  introsort(arr, 0, n - 1, depthLimit);

  return arr;
}

