      arr[k++] = leftArr[i++];
    } else {
      arr[k++] = rightArr[j++];
    }
  }

  while (i < leftArr.length) arr[k++] = leftArr[i++];
  while (j < rightArr.length) arr[k++] = rightArr[j++];
}

export default function optimizedSort(arr: number[]): number[] {
  const n = arr.length;

  if (n <= 1) return arr;
  if (n <= MIN_MERGE) {
    insertionSort(arr, 0, n - 1);
    return arr;
  }

  const minRun = minRunLength(n);

  for (let start = 0; start < n; start += minRun) {
    const end = Math.min(start + minRun - 1, n - 1);
    insertionSort(arr, start, end);
  }

  for (let size = minRun; size < n; size *= 2) {
    for (let left = 0; left < n; left += 2 * size) {
      const mid = Math.min(left + size - 1, n - 1);
      const right = Math.min(left + 2 * size - 1, n - 1);

      if (mid < right) {
        merge(arr, left, mid, right);
      }
    }
  }

  return arr;
}

/**
 * Timsort-based in-place sort optimised for real-world data.
 *
 * Properties:
 *  - O(n) on already-sorted / nearly-sorted input (natural run detection)
 *  - O(n log n) worst-case
 *  - Stable
 *  - Handles arrays up to and well beyond 1 million elements
 */

const MIN_MERGE = 32;

function minRunLength(n: number): number {
  let r = 0;
  while (n >= MIN_MERGE) {
    r |= n & 1;
    n >>= 1;
  }
  return n + r;
}

function insertionSort(
  arr: number[],
  left: number,
  right: number
): void {
  for (let i = left + 1; i <= right; i++) {
    const key = arr[i];
    let j = i - 1;
    while (j >= left && arr[j] > key) {
      arr[j + 1] = arr[j];
      j--;
    }
    arr[j + 1] = key;
  }
}

function reverseRange(arr: number[], lo: number, hi: number): void {
  while (lo < hi) {
    const tmp = arr[lo];
    arr[lo++] = arr[hi];
    arr[hi--] = tmp;
  }
}

/**
 * Locates the end of a natural ascending or descending run starting at `lo`.
 * Descending runs are reversed in-place so they become ascending.
 * Returns the exclusive end index of the run.
 */
function countAndMakeAscendingRun(
  arr: number[],
  lo: number,
  hi: number
): number {
  let runHi = lo + 1;
  if (runHi === hi + 1) return runHi;

  if (arr[runHi++] < arr[lo]) {
    // Descending run — extend and then reverse
    while (runHi <= hi && arr[runHi] < arr[runHi - 1]) runHi++;
    reverseRange(arr, lo, runHi - 1);
  } else {
    // Ascending (non-descending) run — extend
    while (runHi <= hi && arr[runHi] >= arr[runHi - 1]) runHi++;
  }

  return runHi;
}

function merge(
  arr: number[],
  lo: number,
  mid: number,
  hi: number,
  tmp: number[]
): void {
  const leftLen = mid - lo + 1;

  // Copy left half into auxiliary buffer
  for (let i = 0; i < leftLen; i++) tmp[i] = arr[lo + i];

  let l = 0;
  let r = mid + 1;
  let k = lo;

  while (l < leftLen && r <= hi) {
    if (tmp[l] <= arr[r]) {
      arr[k++] = tmp[l++];
    } else {
      arr[k++] = arr[r++];
    }
  }

  while (l < leftLen) arr[k++] = tmp[l++];
  // Elements remaining in the right half are already in place
}

interface Run {
  base: number;
  length: number;
}

function mergeCollapse(
  arr: number[],
  stack: Run[],
  tmp: number[],
  force = false
): void {
  while (stack.length > 1) {
    const n = stack.length - 1;

    const shouldMerge =
      force ||
      (n >= 2 && stack[n - 2].length <= stack[n - 1].length + stack[n].length) ||
      stack[n - 1].length <= stack[n].length;

    if (!shouldMerge) break;

    // Merge the two smallest adjacent runs
    if (n >= 2 && stack[n - 2].length < stack[n].length) {
      // Merge n-2 and n-1
      const lo = stack[n - 2].base;
      const mid = lo + stack[n - 2].length - 1;
      const hi = mid + stack[n - 1].length;
      merge(arr, lo, mid, hi, tmp);
      stack[n - 2] = { base: lo, length: stack[n - 2].length + stack[n - 1].length };
      stack.splice(n - 1, 1);
    } else {
      // Merge n-1 and n
      const lo = stack[n - 1].base;
      const mid = lo + stack[n - 1].length - 1;
      const hi = mid + stack[n].length;
      merge(arr, lo, mid, hi, tmp);
      stack[n - 1] = { base: lo, length: stack[n - 1].length + stack[n].length };
      stack.pop();
    }
  }
}

export default function optimizedSort(arr: number[]): number[] {
  const n = arr.length;

  // Edge cases
  if (n < 2) return arr;

  // Small arrays: plain insertion sort is fastest
  if (n < MIN_MERGE) {
    insertionSort(arr, 0, n - 1);
    return arr;
  }

  const minRun = minRunLength(n);
  const tmp: number[] = new Array(Math.ceil(n / 2));
  const stack: Run[] = [];
  let lo = 0;

  while (lo < n) {
    const hi = n - 1;

    // Detect the natural run starting at `lo`
    let runEnd = countAndMakeAscendingRun(arr, lo, hi);
    let runLen = runEnd - lo;

    // Extend short runs to at least minRun via insertion sort
    if (runLen < minRun) {
      const forcedEnd = Math.min(lo + minRun - 1, hi);
      insertionSort(arr, lo, forcedEnd);
      runLen = forcedEnd - lo + 1;
    }

    stack.push({ base: lo, length: runLen });
    mergeCollapse(arr, stack, tmp);

    lo += runLen;
  }

  // Drain the stack
  mergeCollapse(arr, stack, tmp, true);

  return arr;
}

function optimizedSort(arr: number[]): number[] {
  if (arr.length <= 1) return arr;
  timsort(arr, 0, arr.length - 1);
  return arr;
}

const MIN_MERGE = 32;

function minRunLength(n: number): number {
  let r = 0;
  while (n >= MIN_MERGE) {
    r |= n & 1;
    n >>= 1;
  }
  return n + r;
}

function insertionSort(arr: number[], left: number, right: number): void {
  for (let i = left + 1; i <= right; i++) {
    const temp = arr[i];
    let j = i - 1;
    while (j >= left && arr[j] > temp) {
      arr[j + 1] = arr[j];
      j--;
    }
    arr[j + 1] = temp;
  }
}

function merge(arr: number[], left: number, mid: number, right: number): void {
  const leftArr = arr.slice(left, mid + 1);
  const rightArr = arr.slice(mid + 1, right + 1);

  let i = 0;
  let j = 0;
  let k = left;

  while (i < leftArr.length && j < rightArr.length) {
    if (leftArr[i] <= rightArr[j]) {
      arr[k++] = leftArr[i++];
    } else {
      arr[k++] = rightArr[j++];
    }
  }

  while (i < leftArr.length) arr[k++] = leftArr[i++];
  while (j < rightArr.length) arr[k++] = rightArr[j++];
}

function timsort(arr: number[], left: number, right: number): void {
  const n = right - left + 1;
  const minRun = minRunLength(Math.min(n, MIN_MERGE));

  for (let i = left; i <= right; i += minRun) {
    insertionSort(arr, i, Math.min(i + minRun - 1, right));
  }

  for (let size = minRun; size < n; size *= 2) {
    for (let start = left; start <= right; start += size * 2) {
      const mid = Math.min(start + size - 1, right);
      const end = Math.min(start + size * 2 - 1, right);
      if (mid < end) {
        merge(arr, start, mid, end);
      }
    }
