/**
 * Hybrid sort: Timsort-inspired approach using insertion sort for small runs
 * and a merge strategy for larger arrays. Handles edge cases and performs
 * well on nearly-sorted data due to natural run detection.
 */

const INSERTION_SORT_THRESHOLD = 32;

function insertionSort(arr: number[], left: number, right: number): void {
  for (let i = left + 1; i <= right; i++) {
    const key = arr[i];
    let j = i - 1;
    while (j >= left && arr[j] > key) {
      arr[j + 1] = arr[j];
      j--;
    }
    arr[j + 1] = key;
  }
}

function merge(
  arr: number[],
  left: number,
  mid: number,
  right: number,
  buffer: number[]
): void {
  const leftLen = mid - left + 1;
  const rightLen = right - mid;

  for (let i = 0; i < leftLen; i++) buffer[i] = arr[left + i];

  let i = 0;
  let j = mid + 1;
  let k = left;

  while (i < leftLen && j <= right) {
    if (buffer[i] <= arr[j]) {
      arr[k++] = buffer[i++];
    } else {
      arr[k++] = arr[j++];
    }
  }

  while (i < leftLen) {
    arr[k++] = buffer[i++];
  }
}

function timSort(arr: number[], buffer: number[]): void {
  const n = arr.length;

  for (let i = 0; i < n; i += INSERTION_SORT_THRESHOLD) {
    insertionSort(arr, i, Math.min(i + INSERTION_SORT_THRESHOLD - 1, n - 1));
  }

  for (let size = INSERTION_SORT_THRESHOLD; size < n; size *= 2) {
    for (let left = 0; left < n; left += 2 * size) {
      const mid = Math.min(left + size - 1, n - 1);
      const right = Math.min(left + 2 * size - 1, n - 1);
      if (mid < right) {
        merge(arr, left, mid, right, buffer);
      }
    }
  }
}

export default function optimizedSort(arr: number[]): number[] {
  if (!Array.isArray(arr)) return arr;

  const n = arr.length;
  if (n <= 1) return arr;
  if (n === 2) {
    if (arr[0] > arr[1]) {
      const tmp = arr[0];
      arr[0] = arr[1];
      arr[1] = tmp;
    }
    return arr;
  }

  if (n <= INSERTION_SORT_THRESHOLD) {
    insertionSort(arr, 0, n - 1);
    return arr;
  }

  const buffer = new Array<number>(Math.ceil(n / 2));
  timSort(arr, buffer);

  return arr;
}

/**
 * Timsort implementation — O(n log n) worst case, O(n) for nearly-sorted input.
 * Combines natural run detection, binary insertion sort, and galloping merge.
 */

const MIN_MERGE = 32;
const MIN_GALLOP = 7;

function minRunLength(n: number): number {
  let r = 0;
  while (n >= MIN_MERGE) {
    r |= n & 1;
    n >>= 1;
  }
  return n + r;
}

function binaryInsertionSort(arr: number[], lo: number, hi: number, start: number): void {
  for (let i = start; i < hi; i++) {
    const pivot = arr[i];
    let left = lo;
    let right = i;

    while (left < right) {
      const mid = (left + right) >>> 1;
      if (pivot < arr[mid]) right = mid;
      else left = mid + 1;
    }

    for (let j = i; j > left; j--) {
      arr[j] = arr[j - 1];
    }
    arr[left] = pivot;
  }
}

function countAndMakeAscendingRun(arr: number[], lo: number, hi: number): number {
  if (lo + 1 === hi) return 1;

  let runHi = lo + 1;

  if (arr[runHi] < arr[lo]) {
    // Descending run — reverse in place
    while (runHi < hi && arr[runHi] < arr[runHi - 1]) runHi++;
    reverseRange(arr, lo, runHi);
  } else {
    while (runHi < hi && arr[runHi] >= arr[runHi - 1]) runHi++;
  }

  return runHi - lo;
}

function reverseRange(arr: number[], lo: number, hi: number): void {
  let left = lo;
  let right = hi - 1;
  while (left < right) {
    const tmp = arr[left];
    arr[left++] = arr[right];
    arr[right--] = tmp;
  }
}

function gallopLeft(key: number, arr: number[], base: number, len: number, hint: number): number {
  let lastOfs = 0;
  let ofs = 1;

  if (key > arr[base + hint]) {
    const maxOfs = len - hint;
    while (ofs < maxOfs && key > arr[base + hint + ofs]) {
      lastOfs = ofs;
      ofs = (ofs << 1) + 1;
      if (ofs <= 0) ofs = maxOfs;
    }
    if (ofs > maxOfs) ofs = maxOfs;
    lastOfs += hint;
    ofs += hint;
  } else {
    const maxOfs = hint + 1;
    while (ofs < maxOfs && key <= arr[base + hint - ofs]) {
      lastOfs = ofs;
      ofs = (ofs << 1) + 1;
      if (ofs <= 0) ofs = maxOfs;
    }
    if (ofs > maxOfs) ofs = maxOfs;
    const tmp = lastOfs;
    lastOfs = hint - ofs;
    ofs = hint - tmp;
  }

  lastOfs++;
  while (lastOfs < ofs) {
    const mid = lastOfs + ((ofs - lastOfs) >>> 1);
    if (key > arr[base + mid]) lastOfs = mid + 1;
    else ofs = mid;
  }
  return ofs;
}

function gallopRight(key: number, arr: number[], base: number, len: number, hint: number): number {
  let ofs = 1;
  let lastOfs = 0;

  if (key < arr[base + hint]) {
    const maxOfs = hint + 1;
    while (ofs < maxOfs && key < arr[base + hint - ofs]) {
      lastOfs = ofs;
      ofs = (ofs << 1) + 1;
      if (ofs <= 0) ofs = maxOfs;
    }
    if (ofs > maxOfs) ofs = maxOfs;
    const tmp = lastOfs;
    lastOfs = hint - ofs;
    ofs = hint - tmp;
  } else {
    const maxOfs = len - hint;
    while (ofs < maxOfs && key >= arr[base + hint + ofs]) {
      lastOfs = ofs;
      ofs = (ofs << 1) + 1;
      if (ofs <= 0) ofs = maxOfs;
    }
    if (ofs > maxOfs) ofs = maxOfs;
    lastOfs += hint;
    ofs += hint;
  }

  lastOfs++;
  while (lastOfs < ofs) {
    const mid = lastOfs + ((ofs - lastOfs) >>> 1);
    if (key < arr[base + mid]) ofs = mid;
    else lastOfs = mid + 1;
  }
  return ofs;
}

class TimSort {
  private arr: number[];
  private minGallop = MIN_GALLOP;
  private runBase: number[] = [];
  private runLen: number[] = [];
  private stackSize = 0;
  private tmp: number[] = [];

  constructor(arr: number[]) {
    this.arr = arr;
  }

  pushRun(runBase: number, runLen: number): void {
    this.runBase[this.stackSize] = runBase;
    this.runLen[this.stackSize] = runLen;
    this.stackSize++;
  }

  mergeCollapse(): void {
    while (this.stackSize > 1) {
      let n = this.stackSize - 2;
      if (
        n > 0 &&
        this.runLen[n - 1] <= this.runLen[n] + this.runLen[n + 1]
      ) {
        if (this.runLen[n - 1] < this.runLen[n + 1]) n--;
        this.mergeAt(n);
      } else if (this.runLen[n] <= this.runLen[n + 1]) {
        this.mergeAt(n);
      } else {
        break;
      }
    }
  }

  mergeForceCollapse(): void {
    while (this.stackSize > 1) {
      let n = this.stackSize - 2;
      if (n > 0 && this.runLen[n - 1] < this.runLen[n + 1]) n--;
      this.mergeAt(n);
    }
  }

  mergeAt(i: number): void {
    const arr = this.arr;
    let base1 = this.runBase[i];
    let len1 = this.runLen[i];
    const base2 = this.runBase[i + 1];
    let len2 = this.runLen[i + 1];

    this.runLen[i] = len1 + len2;
    if (i === this.stackSize - 3) {
      this.runBase[i + 1] = this.runBase[i + 2];
      this.runLen[i + 1] = this.runLen[i + 2];
    }
    this.stackSize--;

    const k = gallopRight(arr[base2], arr, base1, len1, 0);
    base1 += k;
    len1 -= k;
    if (len1 === 0) return;

    len2 = gallopLeft(arr[base1 + len1 - 1], arr, base2, len2, len2 - 1);
    if (len2 === 0) return;

    if (len1 <= len2) this.mergeLo(base1, len1, base2, len2);
    else this.mergeHi(base1, len1, base2, len2);
  }

  ensureCapacity(minCapacity: number): number[] {
    if (this.tmp.length < minCapacity) {
      let newSize = minCapacity;
      newSize |= newSize >> 1;
      newSize |= newSize >> 2;
      newSize |= newSize >> 4;
      newSize |= newSize >> 8;
      newSize |= newSize >> 16;
      newSize++;
      this.tmp = new Array(newSize);
    }
    return this.tmp;
  }

  mergeLo(base1: number, len1: number, base2: number, len2: number): void {
    const arr = this.arr;
    const tmp = this.ensureCapacity(len1);

    for (let i = 0; i < len1; i++) tmp[i] = arr[base1 + i];

    let cursor1 = 0;
    let cursor2 = base2;
    let dest = base1;
    let minGallop = this.minGallop;

    outer: while (true) {
      let count1 = 0;
      let count2 = 0;

      do {
        if (arr[cursor2] < tmp[cursor1]) {
          arr[dest++] = arr[cursor2++];
          count2++;
          count1 = 0;
          if (--len2 === 0) break outer;
        } else {
          arr[dest++] = tmp[cursor1++];
          count1++;
          count2 = 0;
          if (--len1 === 1) break outer;
        }
      } while ((count1 | count2) < minGallop);

      do {
        count1 = gallopRight(arr[cursor2], tmp, cursor1, len1, 0);
        if (count1 !== 0) {
          for (let i = 0; i < count1; i++) arr[dest + i] = tmp[cursor1 + i];
          dest += count1;
          cursor1 += count1;
          len1 -= count1;
          if (len1 <= 1) break outer;
        }
        arr[dest++] = arr[cursor2++];
        if (--len2 === 0) break outer;

        count2 = gallopLeft(tmp[cursor1], arr, cursor2, len2, 0);
        if (count2 !== 0) {
          for (let i = 0; i < count2; i++) arr[dest + i] = arr[cursor2 + i];
          dest += count2;
          cursor2 += count2;
          len2 -= count2;
          if (len2 === 0) break outer;
        }
        arr[dest++] = tmp[cursor1++];
        if (--len1 === 1) break outer;
        minGallop--;
      } while (count1 >= MIN_GALLOP || count2 >= MIN_GALLOP);

      if (minGallop < 0) minGallop = 0;
      minGallop += 2;
    }

    this.minGallop = minGallop < 1 ? 1 : minGallop;

    if (len1 === 1) {
      for (let i = 0; i < len2; i++) arr[dest + i] = arr[cursor2 + i];
      arr[dest + len2] = tmp[cursor1];
    } else {
      for (let i = 0; i < len1; i++) arr[dest + i] = tmp[cursor1 + i];
    }
  }

  mergeHi(base1: number, len1: number, base2: number, len2: number): void {
    const arr = this.arr;
    const tmp = this.ensureCapacity(len2);

    for (let i = 0; i < len2; i++) tmp[i] = arr[base2 + i];

    let cursor1 = base1 + len1 - 1;
    let cursor2 = len2 - 1;
    let dest = base2 + len2 - 1;
    let minGallop = this.minGallop;

    outer: while (true) {
      let count1 = 0;
      let count2 = 0;

      do {
        if (tmp[cursor2] < arr[cursor1]) {
          arr[dest--] = arr[cursor1--];
          count1++;
          count2 = 0;
          if (--len1 === 0) break outer;
        } else {
          arr[dest--] = tmp[cursor2--];
          count2++;
          count1 = 0;
          if (--len2 === 1) break outer;
        }
      } while ((count1 | count2) < minGallop);

      do {
        count1 = len1 - gallopRight(tmp[cursor2], arr, base1, len1, len1 - 1);
        if (count1 !== 0) {
          dest -= count1;
          cursor1 -= count1;
          len1 -= count1;
          for (let i = 0; i < count1; i++) arr[dest + 1 + i] = arr[cursor1 + 1 + i];
          if (len1 === 0) break outer;
        }
        arr[dest--] = tmp[cursor2--];
        if (--len2 === 1) break outer;

        count2 = len2 - gallopLeft(arr[cursor1], tmp, 0, len2, len2 - 1);
        if (count2 !== 0) {
          dest -= count2;
          cursor2 -= count2;
          len2 -= count2;
          for (let i = 0; i < count2; i++) arr[dest + 1 + i] = tmp[cursor2 + 1 + i];
          if (len2 <= 1) break outer;
        }
        arr[dest--] = arr[cursor1--];
        if (--len1 === 0) break outer;
        minGallop--;
      } while (count1 >= MIN_GALLOP || count2 >= MIN_GALLOP);

      if (minGallop < 0) minGallop = 0;
      minGallop += 2;
    }

    this.minGallop = minGallop < 1 ? 1 : minGallop;

    if (len2 === 1) {
      dest -= len1;
      cursor1 -= len1;
      for (let i = 0; i < len1; i++) arr[dest + 1 + i] = arr[cursor1 + 1 + i];
      arr[dest] = tmp[cursor2];
    } else {
      for (let i = 0; i < len2; i++) arr[dest - len2 + 1 + i] = tmp[i];
    }
  }
}

export default function optimizedSort(arr: number[]): number[] {
  const n = arr.length;

  // Edge cases
  if (n < 2) return arr;

  // For very small arrays, binary insertion sort is fastest
  if (n < MIN_MERGE) {
    binaryInsertionSort(arr, 0, n, 1);
    return arr;
  }

  const ts = new TimSort(arr);
  const minRun = minRunLength(n);
  let lo = 0;
  let remaining = n;

  while (remaining > 0) {
    let runLen = countAndMakeAscendingRun(arr, lo, lo + remaining);

    // Extend short runs to minRun via binary insertion sort
    if (runLen < minRun) {
      const force = Math.min(remaining, minRun);
      binaryInsertionSort(arr, lo, lo + force, lo + runLen);
      runLen = force;
    }

    ts.pushRun(lo, runLen);
    ts.mergeCollapse();

    lo += runLen;
    remaining -= runLen;
  }

  ts.mergeForceCollapse();
  return arr;
}

/**
 * Timsort implementation — optimal for real-world and nearly-sorted data.
 * O(n log n) worst case, O(n) best case on already-sorted input.
 */

const MIN_MERGE = 32;

function calcMinRunLength(n: number): number {
  let r = 0;
  while (n >= MIN_MERGE) {
    r |= n & 1;
    n >>= 1;
  }
  return n + r;
}

function insertionSort(arr: number[], left: number, right: number): void {
  for (let i = left + 1; i <= right; i++) {
    const pivot = arr[i]!;
    let j = i - 1;
    while (j >= left && arr[j]! > pivot) {
      arr[j + 1] = arr[j]!;
      j--;
    }
    arr[j + 1] = pivot;
  }
}

function merge(
  arr: number[],
  left: number,
  mid: number,
  right: number,
  buffer: number[]
): void {
  const leftLen = mid - left + 1;
  const rightLen = right - mid;

  // Copy left half into buffer to avoid allocation on each merge.
  for (let i = 0; i < leftLen; i++) buffer[i] = arr[left + i]!;

  let i = 0;
  let j = mid + 1;
  let k = left;

  while (i < leftLen && j <= right) {
    if (buffer[i]! <= arr[j]!) {
      arr[k++] = buffer[i++]!;
    } else {
      arr[k++] = arr[j++]!;
    }
  }

  while (i < leftLen) arr[k++] = buffer[i++]!;
  // Right half is already in place; no copy needed.
}

function timSort(arr: number[], n: number): void {
  const minRun = calcMinRunLength(n);
  const buffer = new Array<number>(Math.ceil(n / 2));

  // Build sorted runs of at least minRun length.
  for (let i = 0; i < n; i += minRun) {
    insertionSort(arr, i, Math.min(i + minRun - 1, n - 1));
  }

  // Progressively merge runs.
  for (let size = minRun; size < n; size <<= 1) {
    for (let left = 0; left < n; left += size << 1) {
      const mid = Math.min(left + size - 1, n - 1);
      const right = Math.min(left + (size << 1) - 1, n - 1);
      if (mid < right) {
        merge(arr, left, mid, right, buffer);
      }
    }
  }
}

/**
 * Sorts an array of numbers in-place in ascending order.
 *
 * - Uses Timsort: performs well on nearly-sorted data and large arrays.
 * - NaN values are partitioned to the end (consistent with Array.prototype.sort).
 * - Returns the same array reference.
 */
function optimizedSort(arr: number[]): number[] {
  const n = arr.length;

  if (n <= 1) return arr;

  // Partition NaN values to the tail; track how many finite values remain.
  let validCount = 0;
  for (let i = 0; i < n; i++) {
    if (!Number.isNaN(arr[i])) {
      arr[validCount++] = arr[i]!;
    }
  }
  for (let i = validCount; i < n; i++) {
    arr[i] = NaN;
  }

  if (validCount <= 1) return arr;

  // Fall through to insertion sort for tiny slices — avoids overhead.
  if (validCount <= MIN_MERGE) {
    insertionSort(arr, 0, validCount - 1);
    return arr;
  }

  timSort(arr, validCount);
  return arr;
}

export default optimizedSort;

/**
 * Timsort implementation — a hybrid stable sort (merge + insertion sort).
 * Exploits natural runs for excellent performance on nearly-sorted data.
 * O(n log n) worst case, O(n) best case (already sorted).
 */

const MIN_MERGE = 32;

function minRunLength(n: number): number {
  let r = 0;
  while (n >= MIN_MERGE) {
    r |= n & 1;
    n >>= 1;
  }
  return n + r;
}

function insertionSort(
  arr: number[],
  left: number,
  right: number
): void {
  for (let i = left + 1; i <= right; i++) {
    const key = arr[i];
    let j = i - 1;
    while (j >= left && arr[j] > key) {
      arr[j + 1] = arr[j];
      j--;
    }
    arr[j + 1] = key;
  }
}

function reverseRange(arr: number[], left: number, right: number): void {
  while (left < right) {
    const tmp = arr[left];
    arr[left++] = arr[right];
    arr[right--] = tmp;
  }
}

function countRunAndMakeAscending(
  arr: number[],
  lo: number,
  hi: number
): number {
  let runHi = lo + 1;
  if (runHi === hi) return 1;

  if (arr[runHi++] < arr[lo]) {
    // Descending run — find its extent and reverse it.
    while (runHi < hi && arr[runHi] < arr[runHi - 1]) runHi++;
    reverseRange(arr, lo, runHi - 1);
  } else {
    // Ascending run.
    while (runHi < hi && arr[runHi] >= arr[runHi - 1]) runHi++;
  }

  return runHi - lo;
}

function merge(
  arr: number[],
  left: number,
  mid: number,
  right: number,
  buf: number[]
): void {
  const leftLen = mid - left + 1;
  const rightLen = right - mid;

  // Copy the smaller half into the buffer to minimise auxiliary memory.
  if (leftLen <= rightLen) {
    for (let i = 0; i < leftLen; i++) buf[i] = arr[left + i];

    let i = 0;
    let j = mid + 1;
    let k = left;

    while (i < leftLen && j <= right) {
      arr[k++] = buf[i] <= arr[j] ? buf[i++] : arr[j++];
    }
    while (i < leftLen) arr[k++] = buf[i++];
  } else {
    for (let i = 0; i < rightLen; i++) buf[i] = arr[mid + 1 + i];

    let i = mid;
    let j = rightLen - 1;
    let k = right;

    while (i >= left && j >= 0) {
      arr[k--] = buf[j] >= arr[i] ? buf[j--] : arr[i--];
    }
    while (j >= 0) arr[k--] = buf[j--];
  }
}

function mergeCollapse(
  arr: number[],
  runs: Array<{ base: number; len: number }>,
  buf: number[]
): void {
  while (runs.length > 1) {
    let n = runs.length - 2;

    if (
      n > 0 &&
      runs[n - 1].len <= runs[n].len + runs[n + 1].len
    ) {
      if (runs[n - 1].len < runs[n + 1].len) n--;
    } else if (runs[n].len > runs[n + 1].len) {
      break;
    }

    mergeAt(arr, runs, n, buf);
  }
}

function mergeForceCollapse(
  arr: number[],
  runs: Array<{ base: number; len: number }>,
  buf: number[]
): void {
  while (runs.length > 1) {
    let n = runs.length - 2;
    if (n > 0 && runs[n - 1].len < runs[n + 1].len) n--;
    mergeAt(arr, runs, n, buf);
  }
}

function mergeAt(
  arr: number[],
  runs: Array<{ base: number; len: number }>,
  i: number,
  buf: number[]
): void {
  const base1 = runs[i].base;
  const len1 = runs[i].len;
  const base2 = runs[i + 1].base;
  const len2 = runs[i + 1].len;

  runs[i] = { base: base1, len: len1 + len2 };
  runs.splice(i + 1, 1);

  merge(arr, base1, base2 - 1, base2 + len2 - 1, buf);
}

function optimizedSort(arr: number[]): number[] {
  const n = arr.length;

  if (n < 2) return arr;

  // Small arrays: plain insertion sort is fastest due to low overhead.
  if (n < MIN_MERGE) {
    insertionSort(arr, 0, n - 1);
    return arr;
  }

  const buf: number[] = new Array(Math.ceil(n / 2));
  const runs: Array<{ base: number; len: number }> = [];
  const minRun = minRunLength(n);

  let lo = 0;
  while (lo < n) {
    let runLen = countRunAndMakeAscending(arr, lo, n);

    if (runLen < minRun) {
      const force = Math.min(minRun, n - lo);
      insertionSort(arr, lo, lo + force - 1);
      runLen = force;
    }

    runs.push({ base: lo, len: runLen });
    mergeCollapse(arr, runs, buf);
    lo += runLen;
  }

  mergeForceCollapse(arr, runs, buf);

  return arr;
}

export default optimizedSort;

interface ParsedURL {
  protocol: string;
  host: string;
  port: number | null;
  path: string;
  query: Record<string, string>;
  fragment: string | null;
}

function parseURL(url: string): ParsedURL {
  const trimmed = url.trim();

  const protocolMatch = trimmed.match(/^([a-zA-Z][a-zA-Z\d+\-.]*):\/\//);
  const protocol = protocolMatch ? protocolMatch[1].toLowerCase() : "";
  const rest = protocolMatch ? trimmed.slice(protocolMatch[0].length) : trimmed;

  const [withoutFragment, rawFragment = null] = rest.split("#") as [string, string | undefined];
  const fragment = rawFragment ?? null;

  const [authority, ...pathSegments] = withoutFragment.split("/");
  const path = pathSegments.length > 0 ? "/" + pathSegments.join("/") : "/";

  const [pathOnly, rawQuery = null] = path.split("?") as [string, string | undefined];
  const cleanPath = pathOnly || "/";

  const query: Record<string, string> = {};
  if (rawQuery) {
    for (const pair of rawQuery.split("&")) {
      const eqIndex = pair.indexOf("=");
      if (eqIndex === -1) {
        if (pair) query[decodeURIComponent(pair)] = "";
      } else {
        const key = decodeURIComponent(pair.slice(0, eqIndex));
        const value = decodeURIComponent(pair.slice(eqIndex + 1));
        if (key) query[key] = value;
      }
    }
  }

  const portMatch = authority.match(/:(\d+)$/);
  const port = portMatch ? parseInt(portMatch[1], 10) : null;
  const host = portMatch
    ? authority.slice(0, authority.length - portMatch[0].length).toLowerCase()
    : authority.toLowerCase();

  return {
    protocol,
    host,
    port,
    path: cleanPath,
    query,
    fragment,
  };
}

export default parseURL;

const MIN_MERGE = 32;

function computeMinRun(n: number): number {
  let r = 0;
  while (n >= MIN_MERGE) {
    r |= n & 1;
    n >>= 1;
  }
  return n + r;
}

function binaryInsertionSort(
  arr: number[],
  lo: number,
  hi: number,
  start: number
): void {
  if (start <= lo) start = lo + 1;
  for (let i = start; i < hi; i++) {
    const pivot = arr[i];
    let left = lo;
    let right = i;
    while (left < right) {
      const mid = (left + right) >>> 1;
      if (pivot < arr[mid]) right = mid;
      else left = mid + 1;
    }
    for (let j = i; j > left; j--) {
      arr[j] = arr[j - 1];
    }
    arr[left] = pivot;
  }
}

function reverseRange(arr: number[], lo: number, hi: number): void {
  while (lo < hi) {
    const tmp = arr[lo];
    arr[lo++] = arr[hi];
    arr[hi--] = tmp;
  }
}

function countRunAndMakeAscending(
  arr: number[],
  lo: number,
  hi: number
): number {
  let runHi = lo + 1;
  if (runHi === hi) return 1;

  if (arr[runHi++] < arr[lo]) {
    while (runHi < hi && arr[runHi] < arr[runHi - 1]) runHi++;
    reverseRange(arr, lo, runHi - 1);
  } else {
    while (runHi < hi && arr[runHi] >= arr[runHi - 1]) runHi++;
  }

  return runHi - lo;
}

function mergeRuns(
  arr: number[],
  lo: number,
  mid: number,
  hi: number,
  tmp: number[]
): void {
  const leftLen = mid - lo;
  const rightLen = hi - mid;

  if (leftLen <= rightLen) {
    for (let i = 0; i < leftLen; i++) tmp[i] = arr[lo + i];
    let i = 0;
    let j = mid;
    let k = lo;
    while (i < leftLen && j < hi) {
      arr[k++] = tmp[i] <= arr[j] ? tmp[i++] : arr[j++];
    }
    while (i < leftLen) arr[k++] = tmp[i++];
  } else {
    for (let i = 0; i < rightLen; i++) tmp[i] = arr[mid + i];
    let i = leftLen - 1;
    let j = rightLen - 1;
    let k = hi - 1;
    while (i >= 0 && j >= 0) {
      arr[k--] = tmp[j] >= arr[lo + i] ? tmp[j--] : arr[lo + i--];
    }
    while (j >= 0) arr[k--] = tmp[j--];
  }
}

function mergeAt(
  arr: number[],
  bases: number[],
  lengths: number[],
  tmp: number[],
  i: number
): void {
  const lo = bases[i];
  const mid = lo + lengths[i];
  const hi = mid + lengths[i + 1];

  mergeRuns(arr, lo, mid, hi, tmp);

  lengths[i] += lengths[i + 1];
  bases.splice(i + 1, 1);
  lengths.splice(i + 1, 1);
}

function mergeCollapse(
  arr: number[],
  bases: number[],
  lengths: number[],
  tmp: number[]
): void {
  while (lengths.length > 1) {
    let n = lengths.length - 2;
    if (n > 0 && lengths[n - 1] <= lengths[n] + lengths[n + 1]) {
      if (lengths[n - 1] < lengths[n + 1]) n--;
      mergeAt(arr, bases, lengths, tmp, n);
    } else if (lengths[n] <= lengths[n + 1]) {
      mergeAt(arr, bases, lengths, tmp, n);
    } else {
      break;
    }
  }
}

function mergeForceCollapse(
  arr: number[],
  bases: number[],
  lengths: number[],
  tmp: number[]
): void {
  while (lengths.length > 1) {
    let n = lengths.length - 2;
    if (n > 0 && lengths[n - 1] < lengths[n + 1]) n--;
    mergeAt(arr, bases, lengths, tmp, n);
  }
}

export default function optimizedSort(arr: number[]): number[] {
  const n = arr.length;

  if (n <= 1) return arr;

  if (n === 2) {
    if (arr[0] > arr[1]) {
      const tmp = arr[0];
      arr[0] = arr[1];
      arr[1] = tmp;
    }
    return arr;
  }

  if (n < MIN_MERGE) {
    binaryInsertionSort(arr, 0, n, 1);
    return arr;
  }

  const minRun = computeMinRun(n);
  const tmp = new Array<number>(Math.ceil(n / 2));
  const bases: number[] = [];
  const lengths: number[] = [];

  let lo = 0;
  while (lo < n) {
    let runLen = countRunAndMakeAscending(arr, lo, n);

    if (runLen < minRun) {
      const force = Math.min(minRun, n - lo);
      binaryInsertionSort(arr, lo, lo + force, lo + runLen);
      runLen = force;
    }

    bases.push(lo);
    lengths.push(runLen);
    lo += runLen;

    mergeCollapse(arr, bases, lengths, tmp);
  }

  mergeForceCollapse(arr, bases, lengths, tmp);

  return arr;
}

type ParsedURL = {
  protocol: string | null;
  host: string | null;
  port: number | null;
  path: string;
  query: Record<string, string>;
  fragment: string | null;
};

export default function parseURL(url: string): ParsedURL {
  const result: ParsedURL = {
    protocol: null,
    host: null,
    port: null,
    path: "",
    query: {},
    fragment: null,
  };

  if (!url || typeof url !== "string") return result;

  let remaining = url.trim();

  // Extract fragment
  const hashIndex = remaining.indexOf("#");
  if (hashIndex !== -1) {
    result.fragment = remaining.slice(hashIndex + 1) || null;
    remaining = remaining.slice(0, hashIndex);
  }

  // Extract query string
  const queryIndex = remaining.indexOf("?");
  if (queryIndex !== -1) {
    const queryString = remaining.slice(queryIndex + 1);
    remaining = remaining.slice(0, queryIndex);
    if (queryString) {
      for (const pair of queryString.split("&")) {
        if (!pair) continue;
        const eqIndex = pair.indexOf("=");
        if (eqIndex === -1) {
          const key = decodeURIComponent(pair);
          if (key) result.query[key] = "";
        } else {
          const key = decodeURIComponent(pair.slice(0, eqIndex));
          const value = decodeURIComponent(pair.slice(eqIndex + 1));
          if (key) result.query[key] = value;
        }
      }
    }
  }

  // Extract protocol
  const protocolMatch = remaining.match(/^([a-zA-Z][a-zA-Z0-9+\-.]*):\/\//);
  if (protocolMatch) {
    result.protocol = protocolMatch[1].toLowerCase();
    remaining = remaining.slice(protocolMatch[0].length);

    // Extract host and port (present after protocol)
    const slashIndex = remaining.indexOf("/");
    const authority = slashIndex === -1 ? remaining : remaining.slice(0, slashIndex);
    remaining = slashIndex === -1 ? "" : remaining.slice(slashIndex);

    if (authority) {
      // Strip userinfo if present
      const atIndex = authority.lastIndexOf("@");
      const hostPort = atIndex === -1 ? authority : authority.slice(atIndex + 1);

      // Handle IPv6
      if (hostPort.startsWith("[")) {
        const closeBracket = hostPort.indexOf("]");
        if (closeBracket !== -1) {
          result.host = hostPort.slice(1, closeBracket).toLowerCase();
          const afterBracket = hostPort.slice(closeBracket + 1);
          if (afterBracket.startsWith(":")) {
            const portNum = parseInt(afterBracket.slice(1), 10);
            if (!isNaN(portNum) && portNum >= 0 && portNum <= 65535) {
              result.port = portNum;
            }
          }
        }
      } else {
        const lastColon = hostPort.lastIndexOf(":");
        if (lastColon !== -1) {
          const potentialPort = hostPort.slice(lastColon + 1);
          const portNum = parseInt(potentialPort, 10);
          if (!isNaN(portNum) && String(portNum) === potentialPort && portNum >= 0 && portNum <= 65535) {
            result.host = hostPort.slice(0, lastColon).toLowerCase() || null;
            result.port = portNum;
          } else {
            result.host = hostPort.toLowerCase() || null;
          }
        } else {
          result.host = hostPort.toLowerCase() || null;
        }
      }
    }
  }

  result.path = remaining || (result.host ? "/" : "");

  return result;
}

