const MIN_MERGE = 32;

function minRunLength(n: number): number {
  let r = 0;
  while (n >= MIN_MERGE) {
    r |= n & 1;
    n >>= 1;
  }
  return n + r;
}

function insertionSort(arr: number[], left: number, right: number): void {
  for (let i = left + 1; i <= right; i++) {
    const temp = arr[i];
    let j = i - 1;
    while (j >= left && arr[j] > temp) {
      arr[j + 1] = arr[j];
      j--;
    }
    arr[j + 1] = temp;
  }
}

function merge(arr: number[], left: number, mid: number, right: number): void {
  const leftLen = mid - left + 1;
  const rightLen = right - mid;

  const leftArr = arr.slice(left, mid + 1);
  const rightArr = arr.slice(mid + 1, right + 1);

  let i = 0;
  let j = 0;
  let k = left;

  while (i < leftLen && j < rightLen) {
    if (leftArr[i] <= rightArr[j]) {
      arr[k++] = leftArr[i++];
    } else {
      arr[k++] = rightArr[j++];
    }
  }

  while (i < leftLen) arr[k++] = leftArr[i++];
  while (j < rightLen) arr[k++] = rightArr[j++];
}

function timsort(arr: number[], left: number, right: number): void {
  const n = right - left + 1;
  const minRun = minRunLength(n < MIN_MERGE ? n : MIN_MERGE);

  for (let i = left; i <= right; i += minRun) {
    insertionSort(arr, i, Math.min(i + minRun - 1, right));
  }

  for (let size = minRun; size < n; size *= 2) {
    for (let start = left; start <= right; start += size * 2) {
      const mid = Math.min(start + size - 1, right);
      const end = Math.min(start + size * 2 - 1, right);
      if (mid < end) {
        merge(arr, start, mid, end);
      }
    }
  }
}

