/**
 * Hybrid sort: Timsort-inspired approach using insertion sort for small runs
 * and merge sort for larger arrays. Performs well on nearly-sorted data.
 */

const INSERTION_SORT_THRESHOLD = 32;

function insertionSort(arr: number[], left: number, right: number): void {
  for (let i = left + 1; i <= right; i++) {
    const key = arr[i];
    let j = i - 1;
    while (j >= left && arr[j] > key) {
      arr[j + 1] = arr[j];
      j--;
    }
    arr[j + 1] = key;
  }
}

function merge(arr: number[], left: number, mid: number, right: number, buffer: number[]): void {
  const leftLen = mid - left + 1;
  const rightLen = right - mid;

  for (let i = 0; i < leftLen; i++) buffer[i] = arr[left + i];

  let i = 0;
  let j = mid + 1;
  let k = left;

  while (i < leftLen && j <= right) {
    if (buffer[i] <= arr[j]) {
      arr[k++] = buffer[i++];
    } else {
      arr[k++] = arr[j++];
    }
  }

  while (i < leftLen) {
    arr[k++] = buffer[i++];
  }
}

function timSort(arr: number[], left: number, right: number, buffer: number[]): void {
  const length = right - left + 1;

  if (length <= INSERTION_SORT_THRESHOLD) {
    insertionSort(arr, left, right);
    return;
  }

  const mid = left + Math.floor(length / 2);
  timSort(arr, left, mid, buffer);
  timSort(arr, mid + 1, right, buffer);

  // Skip merge if already in order (optimization for nearly-sorted data)
  if (arr[mid] <= arr[mid + 1]) return;

  merge(arr, left, mid, right, buffer);
}

export default function optimizedSort(arr: number[]): number[] {
  if (!Array.isArray(arr) || arr.length <= 1) return arr;

  const n = arr.length;

  // For very small arrays, insertion sort is optimal
  if (n <= INSERTION_SORT_THRESHOLD) {
    insertionSort(arr, 0, n - 1);
    return arr;
  }

  const buffer = new Array<number>(Math.ceil(n / 2));
  timSort(arr, 0, n - 1, buffer);

  return arr;
}

/**
 * Timsort-inspired hybrid sort optimised for real-world data, including
 * nearly-sorted arrays. Detects natural ascending/descending runs, extends
 * short runs with binary-insertion sort, then merges using a stack-based
 * strategy that maintains the Timsort invariants.
 *
 * Complexity:
 *   Best case  — O(n)   (already sorted)
 *   Average    — O(n log n)
 *   Worst case — O(n log n)
 *   Space      — O(n)   (merge buffer)
 */

const MIN_RUN = 32 as const;

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function reverseRange(arr: number[], lo: number, hi: number): void {
  while (lo < hi) {
    const tmp = arr[lo];
    arr[lo++] = arr[hi];
    arr[hi--] = tmp;
  }
}

/**
 * Binary-insertion sort over arr[lo..hi] (inclusive).
 * `start` is the first unsorted index (elements before it are already sorted).
 */
function binaryInsertionSort(
  arr: number[],
  lo: number,
  hi: number,
  start: number,
): void {
  if (start === lo) start++;

  for (; start <= hi; start++) {
    const pivot = arr[start];

    // Binary search for the correct insertion point within arr[lo..start-1].
    let left = lo;
    let right = start;
    while (left < right) {
      const mid = (left + right) >>> 1;
      if (pivot < arr[mid]) right = mid;
      else left = mid + 1;
    }

    // Shift elements one position to the right to make room.
    for (let j = start; j > left; j--) {
      arr[j] = arr[j - 1];
    }
    arr[left] = pivot;
  }
}

/**
 * Returns the length of the next run beginning at arr[lo], reversing it in
 * place if it is strictly descending so that all runs are non-decreasing.
 */
function countAndNormaliseRun(arr: number[], lo: number, hi: number): number {
  let runHi = lo + 1;
  if (runHi > hi) return 1;

  if (arr[runHi] < arr[lo]) {
    // Strictly descending — find extent, then reverse.
    while (runHi <= hi && arr[runHi] < arr[runHi - 1]) runHi++;
    reverseRange(arr, lo, runHi - 1);
  } else {
    // Non-decreasing — find extent.
    while (runHi <= hi && arr[runHi] >= arr[runHi - 1]) runHi++;
  }

  return runHi - lo;
}

/**
 * Stable in-place merge of arr[lo..mid] and arr[mid+1..hi] using `buf`.
 * Chooses mergeLo or mergeHi depending on which side is smaller to minimise
 * the number of elements copied to the temporary buffer.
 */
function merge(
  arr: number[],
  lo: number,
  mid: number,
  hi: number,
  buf: number[],
): void {
  const len1 = mid - lo + 1;
  const len2 = hi - mid;

  if (len1 <= len2) {
    // Copy the left half into buf and merge forward.
    for (let i = 0; i < len1; i++) buf[i] = arr[lo + i];

    let i = 0; // cursor into buf (left half)
    let j = mid + 1; // cursor into arr (right half)
    let dest = lo;

    while (i < len1 && j <= hi) {
      arr[dest++] = buf[i] <= arr[j] ? buf[i++] : arr[j++];
    }
    while (i < len1) arr[dest++] = buf[i++];
    // Remaining right-half elements are already in place.
  } else {
    // Copy the right half into buf and merge backward.
    for (let i = 0; i < len2; i++) buf[i] = arr[mid + 1 + i];

    let i = mid; // cursor into arr (left half), moving left
    let j = len2 - 1; // cursor into buf (right half), moving left
    let dest = hi;

    while (i >= lo && j >= 0) {
      arr[dest--] = arr[i] > buf[j] ? arr[i--] : buf[j--];
    }
    while (j >= 0) arr[dest--] = buf[j--];
    // Remaining left-half elements are already in place.
  }
}

// ---------------------------------------------------------------------------
// Run stack maintenance
// ---------------------------------------------------------------------------

interface Run {
  base: number;
  len: number;
}

/**
 * Enforce the two Timsort invariants on the run stack:
 *   1. runStack[i].len > runStack[i+1].len + runStack[i+2].len
 *   2. runStack[i].len > runStack[i+1].len
 *
 * Violations are resolved by merging the smaller of the two candidate pairs.
 */
function mergeCollapse(
  arr: number[],
  stack: Run[],
  buf: number[],
  force: boolean,
): void {
  while (stack.length > 1) {
    const n = stack.length - 1;

    const shouldMerge =
      force ||
      (stack.length >= 3 &&
        stack[n - 2].len <= stack[n - 1].len + stack[n].len) ||
      stack[n - 1].len <= stack[n].len;

    if (!shouldMerge) break;

    if (
      stack.length >= 3 &&
      stack[n - 2].len < stack[n].len
    ) {
      // Merge the penultimate two runs (index n-2 and n-1).
      const a = stack[n - 2];
      const b = stack[n - 1];
      merge(arr, a.base, a.base + a.len - 1, b.base + b.len - 1, buf);
      stack[n - 2] = { base: a.base, len: a.len + b.len };
      stack.splice(n - 1, 1);
    } else {
      // Merge the last two runs (index n-1 and n).
      const a = stack[n - 1];
      const b = stack[n];
      merge(arr, a.base, a.base + a.len - 1, b.base + b.len - 1, buf);
      stack[n - 1] = { base: a.base, len: a.len + b.len };
      stack.pop();
    }
  }
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

function optimizedSort(arr: number[]): number[] {
  // --- Edge cases -----------------------------------------------------------
  if (!Array.isArray(arr)) return arr;

  const n = arr.length;
  if (n <= 1) return arr;

  // Replace non-finite values with a canonical sentinel so the comparisons
  // below never produce NaN (which would break the sort invariant).
  // NaN → treated as +Infinity; keeps parity with JS built-in sort.
  for (let i = 0; i < n; i++) {
    if (!Number.isFinite(arr[i])) {
      // Leave Infinity / -Infinity as-is; replace NaN.
      if (Number.isNaN(arr[i])) arr[i] = Number.POSITIVE_INFINITY;
    }
  }

  // Small arrays are sorted entirely with insertion sort — no overhead.
  if (n <= MIN_RUN) {
    binaryInsertionSort(arr, 0, n - 1, 0);
    return arr;
  }

  // --- Main Timsort loop ----------------------------------------------------

  // A shared buffer sized to the larger half avoids repeated allocations.
  const buf: number[] = new Array(Math.ceil(n / 2));
  const stack: Run[] = [];
  let lo = 0;

  while (lo < n) {
    // Detect a natural run.
    let runLen = countAndNormaliseRun(arr, lo, n - 1);

    // If the run is shorter than MIN_RUN, extend it with insertion sort.
    if (runLen < MIN_RUN) {
      const forcedLen = Math.min(MIN_RUN, n - lo);
      binaryInsertionSort(arr, lo, lo + forcedLen - 1, lo + runLen);
      runLen = forcedLen;
    }

    stack.push({ base: lo, len: runLen });
    mergeCollapse(arr, stack, buf, false);

    lo += runLen;
  }

  // Drain the stack — merge all remaining runs.
  mergeCollapse(arr, stack, buf, true);

  return arr;
}

