  let gt = right - 1;
  let i = left;

  while (i <= gt) {
    if (arr[i] < pivot) {
      [arr[lt], arr[i]] = [arr[i], arr[lt]];
      lt++;
      i++;
    } else if (arr[i] > pivot) {
      [arr[gt], arr[i]] = [arr[i], arr[gt]];
      gt--;
