  left: number,
  right: number,
  depthLimit: number
): void {
  const size = right - left + 1;

  if (size <= INSERTION_THRESHOLD) {
    insertionSort(arr, left, right);
    return;
  }

  if (depthLimit === 0) {
    heapsortRange(arr, left, right);
    return;
  }

  const [lt, gt] = partition(arr, left, right);

  introsort(arr, left, lt - 1, depthLimit - 1);
  introsort(arr, gt + 1, right, depthLimit - 1);
