  const n = right - left + 1;

  for (let i = Math.floor(n / 2) - 1; i >= 0; i--) {
    siftDown(arr, i, n - 1, left);
  }

  for (let i = n - 1; i > 0; i--) {
    [arr[left], arr[left + i]] = [arr[left + i], arr[left]];
    siftDown(arr, 0, i - 1, left);
  }
