function siftDown(
  arr: number[],
  root: number,
  end: number,
  offset: number
): void {
  while (true) {
    let largest = root;
    const left = 2 * root + 1;
    const right = 2 * root + 2;

    if (left <= end && arr[offset + left] > arr[offset + largest]) {
      largest = left;
    }
    if (right <= end && arr[offset + right] > arr[offset + largest]) {
      largest = right;
    }

    if (largest === root) break;

    [arr[offset + root], arr[offset + largest]] = [
      arr[offset + largest],
      arr[offset + root],
    ];
    root = largest;
  }
}

