/**
 * Hybrid sort: insertion sort for small arrays, Timsort-inspired merge sort
 * with galloping for large arrays. Handles edge cases and performs well on
 * nearly-sorted data.
 */

const RUN = 32;

function insertionSort(arr: number[], left: number, right: number): void {
  for (let i = left + 1; i <= right; i++) {
    const key = arr[i];
    let j = i - 1;
    while (j >= left && arr[j] > key) {
      arr[j + 1] = arr[j];
      j--;
    }
    arr[j + 1] = key;
  }
}

function merge(arr: number[], left: number, mid: number, right: number): void {
  const leftLen = mid - left + 1;
  const rightLen = right - mid;

  const leftArr = arr.slice(left, mid + 1);
  const rightArr = arr.slice(mid + 1, right + 1);

  let i = 0;
  let j = 0;
  let k = left;

  // Galloping mode threshold
  const MIN_GALLOP = 7;
  let gallopLeft = 0;
  let gallopRight = 0;

  while (i < leftLen && j < rightLen) {
    if (leftArr[i] <= rightArr[j]) {
      arr[k++] = leftArr[i++];
      gallopLeft++;
      gallopRight = 0;

      if (gallopLeft >= MIN_GALLOP) {
        // Gallop through leftArr
        let gallop = 1;
        while (i + gallop < leftLen && leftArr[i + gallop] <= rightArr[j]) {
          gallop *= 2;
        }
        const end = Math.min(i + gallop, leftLen);
        while (i < end && leftArr[i] <= rightArr[j]) {
          arr[k++] = leftArr[i++];
        }
        gallopLeft = 0;
      }
    } else {
      arr[k++] = rightArr[j++];
      gallopRight++;
      gallopLeft = 0;

      if (gallopRight >= MIN_GALLOP) {
        // Gallop through rightArr
        let gallop = 1;
        while (j + gallop < rightLen && rightArr[j + gallop] < leftArr[i]) {
          gallop *= 2;
        }
        const end = Math.min(j + gallop, rightLen);
        while (j < end && rightArr[j] < leftArr[i]) {
          arr[k++] = rightArr[j++];
        }
        gallopRight = 0;
      }
    }
  }

  while (i < leftLen) arr[k++] = leftArr[i++];
  while (j < rightLen) arr[k++] = rightArr[j++];
}

export default function optimizedSort(arr: number[]): number[] {
  if (!Array.isArray(arr)) return arr;

  const n = arr.length;

  if (n <= 1) return arr;
  if (n === 2) {
